code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, icon } from 'decantr/components';

code.example:
function KpiGrid({ items }) {
  const { div, span, p } = tags;

  const kpis = items || [
    { label: 'Total Revenue', value: '$45,231', change: '+20.1%', trend: 'up', ic: 'dollar-sign' },
    { label: 'Subscriptions', value: '2,350', change: '+180', trend: 'up', ic: 'users' },
    { label: 'Active Now', value: '573', change: '+19', trend: 'up', ic: 'activity' },
    { label: 'Bounce Rate', value: '24.5%', change: '-4.3%', trend: 'down', ic: 'trending-down' },
  ];

  return div({ class: css('_grid _gc2 _lg:gc4 _gap4') },
    ...kpis.map(kpi =>
      Card({ class: css('_flex _col _gap2 _p4') },
        div({ class: css('_flex _jcsb _aic') },
          span({ class: css('_textsm _fgmuted') }, kpi.label),
          icon(kpi.ic, { size: '1rem', class: css('_fgmuted') })
        ),
        p({ class: css('_heading2') }, kpi.value),
        Badge({ variant: kpi.trend === 'up' ? 'default' : 'secondary' }, kpi.change)
      )
    )
  );
}

